"use client"

import React, { useCallback, useEffect, useMemo, useRef, useState } from "react"
import { useAtomSet, useAtomValue } from "@effect-atom/atom-react"
import { Exit, Layer, ManagedRuntime, Option } from "effect"
import { keypairAtom, packedKeyAtom } from "@/atoms/falcon"
import {
  deployStepAtom,
  deployedAddressAtom,
  deployTxHashAtom,
  networkAtom,
} from "@/atoms/starknet"
import { NETWORKS } from "@/config/networks"
import type { NetworkConfig } from "@/config/networks"
import { FalconService } from "@/services/FalconService"
import { FalconSigner } from "@/services/FalconSigner"
import { StarknetService } from "@/services/StarknetService"
import { WasmRuntimeLive } from "@/services/WasmRuntime"
import type { DevnetAccount } from "@/services/types"
import { SendTransaction } from "./SendTransaction"
import { extractUserMessage } from "@/services/error-messages"
import { AddressDisplay } from "@/components/ui/AddressDisplay"
import { ExplorerLink } from "@/components/ui/ExplorerLink"
import { TokenAmount } from "@/components/ui/TokenAmount"
import { TransactionPending } from "@/components/ui/TransactionPending"
import type { PreparedAccountDeploy } from "./accountDeployPipeline"
import {
  deployAccountEffect,
  prepareAccountDeployEffect,
} from "./accountDeployPipeline"

const falconRuntime = ManagedRuntime.make(
  FalconService.Default.pipe(Layer.provide(WasmRuntimeLive)),
)

function createDeployRuntime(config: NetworkConfig) {
  return ManagedRuntime.make(
    Layer.mergeAll(
      FalconService.Default.pipe(Layer.provide(WasmRuntimeLive)),
      StarknetService.make(config.rpcUrl, config.classHash),
    ),
  )
}


export function AccountDeployFlow(): React.JSX.Element {
  const keypair = useAtomValue(keypairAtom)
  const packedKey = useAtomValue(packedKeyAtom)
  const deployStep = useAtomValue(deployStepAtom)
  const setKeypair = useAtomSet(keypairAtom)
  const setDeployStep = useAtomSet(deployStepAtom)
  const setDeployedAddress = useAtomSet(deployedAddressAtom)
  const setDeployTxHash = useAtomSet(deployTxHashAtom)
  const networkId = useAtomValue(networkAtom)
  const networkConfig = NETWORKS[networkId]

  const deployRuntimeRef = useRef(createDeployRuntime(networkConfig))
  const prevNetworkRef = useRef(networkId)
  if (prevNetworkRef.current !== networkId) {
    prevNetworkRef.current = networkId
    deployRuntimeRef.current = createDeployRuntime(networkConfig)
  }

  const [privateKey, setPrivateKey] = useState("")
  const [devnetAccounts, setDevnetAccounts] = useState<DevnetAccount[]>([])
  const [preparedDeploy, setPreparedDeploy] =
    useState<Option.Option<PreparedAccountDeploy>>(Option.none())
  const [balance, setBalance] = useState<bigint | null>(null)
  const [postDeployBalance, setPostDeployBalance] = useState<bigint | null>(null)
  const [autoRestoring, setAutoRestoring] = useState(false)
  const [deployStartTime, setDeployStartTime] = useState<number | null>(null)
  const [lastChecked, setLastChecked] = useState<number | null>(null)
  const [isRefreshing, setIsRefreshing] = useState(false)

  // ── Auto-restore: if keypair+packedKey exist in localStorage, restore flow state ──
  const autoRestoreRan = useRef(false)
  useEffect(() => {
    if (autoRestoreRan.current) return
    if (!Option.isSome(keypair) || !Option.isSome(packedKey)) return
    if (deployStep.step !== "idle") return
    if (networkConfig.classHash === "0x0") return

    autoRestoreRan.current = true
    setAutoRestoring(true)

    const restore = async () => {
      // Prepare using existing keypair
      const prepareExit = await deployRuntimeRef.current.runPromiseExit(
        prepareAccountDeployEffect({
          privateKey: "",
          existingKeypair: keypair,
        }),
      )

      if (Exit.isFailure(prepareExit)) {
        setAutoRestoring(false)
        return
      }

      const prepared = prepareExit.value
      setPreparedDeploy(Option.some(prepared))

      // Check if already deployed on-chain
      const deployedExit = await deployRuntimeRef.current.runPromiseExit(
        StarknetService.isDeployed(prepared.address),
      )

      if (Exit.isSuccess(deployedExit) && deployedExit.value) {
        // Already deployed — skip straight to deployed state
        setDeployedAddress(Option.some(prepared.address))
        setDeployTxHash(Option.some("already-deployed" as any))
        setDeployStep({
          step: "deployed",
          txHash: "already-deployed" as any,
          address: prepared.address,
        })
        setAutoRestoring(false)
        return
      }

      // Not deployed — check balance and go to awaiting-funds
      setDeployStep({ step: "awaiting-funds", address: prepared.address })
      setAutoRestoring(false)
    }

    restore()
  }, [keypair, packedKey, deployStep.step, networkConfig.classHash, setDeployStep, setDeployedAddress, setDeployTxHash])

  // Reset on network change
  useEffect(() => {
    setDeployStep({ step: "idle" })
    setPreparedDeploy(Option.none())
    setBalance(null)
    autoRestoreRan.current = false
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [networkId])

  useEffect(() => {
    if (!networkConfig.isDevnet) {
      setDevnetAccounts([])
      return
    }
    let cancelled = false
    const fetchAccounts = async () => {
      const exit = await deployRuntimeRef.current.runPromiseExit(
        StarknetService.fetchPrefundedAccounts(),
      )
      if (!cancelled && Exit.isSuccess(exit)) {
        setDevnetAccounts(exit.value)
        if (exit.value.length > 0) {
          setPrivateKey(exit.value[0].private_key)
        }
      }
    }
    fetchAccounts()
    return () => { cancelled = true }
  }, [networkConfig.isDevnet])

  const hasKeypair = Option.isSome(keypair)

  const pollBalance = useCallback(async (address: string) => {
    const exit = await deployRuntimeRef.current.runPromiseExit(
      StarknetService.getBalance(address),
    )
    if (Exit.isSuccess(exit)) {
      setBalance(exit.value)
      setLastChecked(Date.now())
    }
  }, [])

  useEffect(() => {
    if (deployStep.step !== "awaiting-funds") {
      setBalance(null)
      setLastChecked(null)
      return
    }

    let cancelled = false

    const poll = async () => {
      if (cancelled) return
      await pollBalance(deployStep.address)
    }

    poll()
    const interval = setInterval(poll, 5000)
    return () => {
      cancelled = true
      clearInterval(interval)
    }
  }, [deployStep, pollBalance])

  const handleRefreshBalance = useCallback(async () => {
    if (deployStep.step !== "awaiting-funds") return
    setIsRefreshing(true)
    await pollBalance(deployStep.address)
    setIsRefreshing(false)
  }, [deployStep, pollBalance])

  const handlePrepare = useCallback(async () => {
    setDeployStep({ step: hasKeypair ? "packing" : "generating-keypair" })
    setDeployTxHash(Option.none())
    setDeployedAddress(Option.none())
    setPreparedDeploy(Option.none())

    const prepareExit = await deployRuntimeRef.current.runPromiseExit(
      prepareAccountDeployEffect({
        privateKey,
        existingKeypair: keypair,
      }),
    )

    if (Exit.isFailure(prepareExit)) {
      setDeployStep({
        step: "error",
        message: extractUserMessage(prepareExit, "Failed to prepare deployment"),
      })
      return
    }

    const prepared = prepareExit.value
    setPreparedDeploy(Option.some(prepared))
    setKeypair(Option.some(prepared.keypair))
    setDeployStep({ step: "awaiting-funds", address: prepared.address })
  }, [
    hasKeypair,
    keypair,
    privateKey,
    setDeployStep,
    setDeployTxHash,
    setDeployedAddress,
    setKeypair,
  ])

  const handleDeploy = useCallback(async () => {
    const prepared = Option.match(preparedDeploy, {
      onNone: () => null,
      onSome: (value) => value,
    })
    if (prepared === null) {
      setDeployStep({
        step: "error",
        message: "Prepare the deployment before submitting.",
      })
      return
    }

    setDeployStep({ step: "deploying", address: prepared.address })
    setDeployStartTime(Date.now())
    const signer = new FalconSigner(
      prepared.keypair.secretKey,
      prepared.keypair.publicKeyNtt,
      falconRuntime,
    )
    const deployExit = await deployRuntimeRef.current.runPromiseExit(
      deployAccountEffect({
        address: prepared.address,
        packedPublicKey: prepared.packedPublicKey,
        signer,
        salt: prepared.salt,
        requiredBalance: 1n,
      }),
    )

    if (Exit.isFailure(deployExit)) {
      setDeployStep({
        step: "error",
        message: extractUserMessage(deployExit, "Account deployment failed"),
      })
      return
    }

    setDeployTxHash(Option.some(deployExit.value.txHash))
    setDeployedAddress(Option.some(deployExit.value.address))
    setDeployStep({
      step: "deployed",
      txHash: deployExit.value.txHash,
      address: deployExit.value.address,
    })
    setDeployStartTime(null)

    // Fetch remaining balance after deploy
    const balExit = await deployRuntimeRef.current.runPromiseExit(
      StarknetService.getBalance(deployExit.value.address),
    )
    if (Exit.isSuccess(balExit)) {
      setPostDeployBalance(balExit.value)
    }

    // Smooth scroll to send section
    setTimeout(() => {
      document.getElementById("send-section")?.scrollIntoView({ behavior: "smooth", block: "start" })
    }, 300)
  }, [preparedDeploy, setDeployStep, setDeployTxHash, setDeployedAddress])

  const handleReset = useCallback(() => {
    setPreparedDeploy(Option.none())
    setDeployTxHash(Option.none())
    setDeployedAddress(Option.none())
    setDeployStep({ step: "idle" })
    autoRestoreRan.current = false
  }, [setDeployStep, setDeployTxHash, setDeployedAddress])

  const stepFlags = useMemo(() => {
    const stepName = deployStep.step

    const step1Complete =
      hasKeypair ||
      stepName === "packing" ||
      stepName === "computing-address" ||
      stepName === "awaiting-funds" ||
      stepName === "deploying" ||
      stepName === "deployed"

    const step2Complete =
      stepName === "computing-address" ||
      stepName === "awaiting-funds" ||
      stepName === "deploying" ||
      stepName === "deployed"

    const step3Complete =
      stepName === "awaiting-funds" ||
      stepName === "deploying" ||
      stepName === "deployed"

    const step4Complete = stepName === "deploying" || stepName === "deployed"
    const step5Complete = stepName === "deployed"

    return {
      step1Active: stepName === "generating-keypair",
      step2Active: stepName === "packing",
      step3Active: stepName === "computing-address",
      step4Active: stepName === "awaiting-funds",
      step5Active: stepName === "deploying",
      step1Complete,
      step2Complete,
      step3Complete,
      step4Complete,
      step5Complete,
    }
  }, [deployStep.step, hasKeypair])

  const liveStatus = useMemo(() => {
    switch (deployStep.step) {
      case "idle":
        return "Account deploy flow is idle."
      case "generating-keypair":
        return "Generating Falcon keypair."
      case "packing":
        return "Packing Falcon public key."
      case "computing-address":
        return "Computing Starknet deploy address."
      case "awaiting-funds":
        return `Waiting for funds at ${deployStep.address}.`
      case "deploying":
        return "Deploying account transaction."
      case "deployed":
        return `Account deployed with transaction hash ${deployStep.txHash}.`
      case "error":
        return deployStep.message
    }
  }, [deployStep])

  const isAlreadyDeployed = deployStep.step === "deployed" && deployStep.txHash === "already-deployed"

  const DEPLOY_STEPS = [
    { number: 1, title: "Generate Keypair", description: "Create or reuse a Falcon-512 keypair.", active: stepFlags.step1Active, complete: stepFlags.step1Complete },
    { number: 2, title: "Pack Public Key", description: "Compress public key into 29 felt252 slots.", active: stepFlags.step2Active, complete: stepFlags.step2Complete },
    { number: 3, title: "Compute Address", description: "Compute the counterfactual address.", active: stepFlags.step3Active, complete: stepFlags.step3Complete },
    { number: 4, title: "Fund Account", description: "Send STRK to the pre-computed address.", active: stepFlags.step4Active, complete: stepFlags.step4Complete },
    { number: 5, title: "Deploy", description: "Broadcast and confirm deploy transaction.", active: stepFlags.step5Active, complete: stepFlags.step5Complete },
  ]

  return (
    <section id="deploy" className="px-8 py-32 lg:px-8">
      <div className="mx-auto max-w-6xl">
        <h2 className="text-4xl font-semibold tracking-[-0.02em] text-falcon-text">Deploy your own quantum-safe account</h2>
        <p className="mt-4 text-sm leading-relaxed text-falcon-text/50">
          Deploy a Falcon-powered account to Starknet {networkConfig.name} &mdash; takes about 60 seconds.
          Uses the same keypair from the playground above.
        </p>
        {networkConfig.classHash === "0x0" && (
          <div className="glass-card-static glass-card-warning mt-6 rounded-2xl p-5">
            <p className="text-sm text-yellow-400/80">
              FalconAccount not declared on {networkConfig.name}.
              Run: <code className="glass-display rounded-md px-1.5 py-0.5 font-mono text-xs">./bin/declare.sh {networkConfig.id}</code>
            </p>
          </div>
        )}
        <p className="sr-only" aria-live="polite">
          {liveStatus}
        </p>

        {/* Auto-restore loading state */}
        {autoRestoring && (
          <div className="mt-8 flex items-center gap-3 text-sm text-falcon-text/40">
            <div className="h-4 w-4 animate-spin rounded-full border-2 border-falcon-primary/30 border-t-falcon-primary" />
            Restoring your wallet...
          </div>
        )}

        {/* Vertical progress line with step cards */}
        {!autoRestoring && (
          <div className="relative mt-10 space-y-0">
            {/* Vertical line */}
            <div
              className="absolute left-[19px] top-4 bottom-4 w-px bg-falcon-muted/15"
            />

            {DEPLOY_STEPS.map((s) => (
              <div key={s.number} className="relative flex items-start gap-5 py-3">
                {/* Step dot/check on the line */}
                <div className="relative z-10 flex h-10 w-10 shrink-0 items-center justify-center">
                  <div
                    className={`flex h-8 w-8 items-center justify-center rounded-full text-xs font-semibold transition-all duration-300 ${
                      s.complete
                        ? "bg-falcon-success/15 text-falcon-success"
                        : s.active
                          ? "bg-falcon-primary/15 text-falcon-primary shadow-[0_0_12px_rgba(99,102,241,0.3)]"
                          : "text-falcon-text/40 bg-falcon-muted/10 border border-falcon-muted/20"
                    }`}
                  >
                    {s.complete ? "\u2713" : s.number}
                  </div>
                </div>

                {/* Step content */}
                <div className="flex-1 pb-2">
                  <h3 className={`text-sm font-semibold transition-colors duration-200 ${
                    s.active ? "text-falcon-text" : s.complete ? "text-falcon-text/60" : "text-falcon-text/40"
                  }`}>
                    {s.title}
                  </h3>
                  <p className="mt-0.5 text-xs text-falcon-text/25">{s.description}</p>

                  {/* Fund Account expanded content */}
                  {s.number === 4 && deployStep.step === "awaiting-funds" && (
                    <div className="mt-4 space-y-3">
                      <div className="glass-card-static rounded-xl p-4">
                        <p className="text-[10px] font-medium tracking-widest text-falcon-text/20 uppercase">Send STRK to</p>
                        <AddressDisplay
                          address={deployStep.address}
                          explorerBaseUrl={networkConfig.explorerBaseUrl}
                          className="mt-2"
                        />
                      </div>
                      {networkConfig.isTestnet && !networkConfig.isDevnet && (
                        <a
                          href="https://starknet-faucet.vercel.app/"
                          target="_blank"
                          rel="noreferrer noopener"
                          className="inline-block text-xs text-falcon-accent/60 transition-colors duration-200 hover:text-falcon-accent"
                        >
                          Get testnet STRK from the Starknet Faucet &rarr;
                        </a>
                      )}
                      {balance !== null && (
                        <div className="flex items-center gap-2 text-xs text-falcon-text/30">
                          <span>Balance:</span>
                          <TokenAmount amount={balance} className={balance > 0n ? "text-falcon-success/80" : "text-falcon-text/30"} />
                          {balance > 0n && (
                            <span className="text-falcon-success/60">Ready to deploy</span>
                          )}
                          <button
                            onClick={handleRefreshBalance}
                            disabled={isRefreshing}
                            className="ml-1 inline-flex items-center gap-1 rounded-md px-1.5 py-0.5 text-[10px] text-falcon-text/25 transition-colors hover:text-falcon-text/50 disabled:opacity-40"
                            title="Refresh balance"
                          >
                            {isRefreshing ? (
                              <span className="inline-block h-3 w-3 animate-spin rounded-full border border-falcon-text/20 border-t-falcon-text/50" />
                            ) : (
                              "Refresh"
                            )}
                          </button>
                          {lastChecked != null && (
                            <LastCheckedAgo timestamp={lastChecked} />
                          )}
                        </div>
                      )}
                    </div>
                  )}
                </div>
              </div>
            ))}
          </div>
        )}

        {!autoRestoring && (
          <div className="mt-8 space-y-3">
            {networkConfig.isDevnet && devnetAccounts.length > 0 ? (
              <div>
                <label htmlFor="devnet-account" className="block text-xs font-medium text-falcon-text/30">
                  Deployer Account
                </label>
                <select
                  id="devnet-account"
                  value={privateKey}
                  onChange={(e) => setPrivateKey(e.target.value)}
                  className="glass-select mt-2 w-full px-4 py-3 font-mono text-sm text-falcon-text/80"
                >
                  {devnetAccounts.map((acc, i) => (
                    <option key={acc.address} value={acc.private_key}>
                      Account #{i} ({acc.address.slice(0, 10)}...{acc.address.slice(-4)})
                    </option>
                  ))}
                </select>
              </div>
            ) : null}

            {deployStep.step === "idle" && (() => {
              const classHashValid = networkConfig.classHash !== "0x0"
              return (
                <button
                  onClick={handlePrepare}
                  disabled={!classHashValid}
                  className={`rounded-xl px-7 py-3 text-sm font-semibold transition-all duration-200 active:scale-[0.98] focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-falcon-primary/40 ${
                    classHashValid
                      ? "bg-gradient-to-b from-falcon-primary to-falcon-primary/80 text-white shadow-md shadow-falcon-primary/15 hover:scale-[1.02] hover:shadow-lg hover:shadow-falcon-primary/20"
                      : "glass-btn cursor-not-allowed opacity-40 text-falcon-text/40"
                  }`}
                >
                  Prepare Deploy
                </button>
              )
            })()}

            {deployStep.step === "awaiting-funds" && (
              <button
                onClick={handleDeploy}
                className="rounded-xl bg-gradient-to-b from-falcon-accent to-falcon-accent/80 px-7 py-3 text-sm font-semibold text-white shadow-md shadow-falcon-accent/15 transition-all duration-200 hover:scale-[1.02] hover:shadow-lg hover:shadow-falcon-accent/20 active:scale-[0.98] focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-falcon-accent/40"
              >
                Deploy Account
              </button>
            )}
          </div>
        )}

        {deployStep.step === "deploying" && (
          <TransactionPending
            title="Deploying account..."
            subtitle={`Signing with Falcon-512 and submitting to ${networkConfig.name}`}
            startTime={deployStartTime ?? undefined}
            hint="Falcon verification takes ~30-60 seconds on testnet"
          />
        )}

        {deployStep.step === "deployed" && (
          <>
            <div
              role="status"
              aria-live="polite"
              className="glass-card-static glass-card-success mt-8 rounded-2xl p-6 animate-fade-in animate-success-shimmer"
            >
              <h3 className="text-sm font-semibold text-falcon-success/80">
                {isAlreadyDeployed ? "Account Already Deployed" : "Account Deployed"}
              </h3>
              <AddressDisplay
                label="Address"
                address={deployStep.address}
                explorerBaseUrl={networkConfig.explorerBaseUrl}
                className="mt-3"
              />
              {!isAlreadyDeployed && (
                <>
                  <p className="mt-2 break-all font-mono tabular-nums text-xs text-falcon-text/50">
                    Tx: {deployStep.txHash}
                  </p>
                  <ExplorerLink baseUrl={networkConfig.explorerBaseUrl} txHash={deployStep.txHash} className="mt-3" />
                </>
              )}
              {postDeployBalance != null && (
                <div className="mt-3 flex items-center gap-2 text-xs text-falcon-text/30">
                  <span>Remaining balance:</span>
                  <TokenAmount amount={postDeployBalance} className="text-falcon-text/50" />
                </div>
              )}
            </div>
            <div id="send-section">
              <SendTransaction
                deployedAddress={deployStep.address}
                deployRuntime={deployRuntimeRef.current}
                falconRuntime={falconRuntime}
              />
            </div>
          </>
        )}

        {deployStep.step === "error" && (
          <div
            role="alert"
            aria-live="polite"
            className="glass-card-static glass-card-error mt-8 rounded-2xl p-6 animate-fade-in"
          >
            <p className="text-sm text-falcon-error/80">{deployStep.message}</p>
            <button
              onClick={handleReset}
              className="glass-btn mt-4 rounded-lg px-4 py-1.5 text-xs text-falcon-text/40 hover:text-falcon-text/70"
            >
              Try Again
            </button>
          </div>
        )}
      </div>
    </section>
  )
}

function LastCheckedAgo({ timestamp }: { timestamp: number }) {
  const [ago, setAgo] = useState(0)

  useEffect(() => {
    const tick = () => setAgo(Math.floor((Date.now() - timestamp) / 1000))
    tick()
    const interval = setInterval(tick, 1000)
    return () => clearInterval(interval)
  }, [timestamp])

  return (
    <span className="text-[10px] text-falcon-text/20 tabular-nums">
      {ago}s ago
    </span>
  )
}

"use client"

import React, { useCallback, useEffect, useState } from "react"
import { Cause, Exit, Layer, ManagedRuntime, Option } from "effect"
import { useAtomValue, useAtomSet } from "@effect-atom/atom-react"
import { hash } from "starknet"
import { FalconService } from "@/services/FalconService"
import { WasmRuntimeLive } from "@/services/WasmRuntime"
import {
  keypairAtom,
  packedKeyAtom,
  verificationStepAtom,
  wasmStatusAtom,
  persistKeypair,
  persistPackedKey,
  getExportedFlag,
  setExportedFlag,
} from "@/atoms/falcon"
import { networkAtom } from "@/atoms/starknet"
import { NETWORKS } from "@/config/networks"
import { exportKeyFile, parseKeyFile } from "@/services/keyfile"
import type { PackedPublicKey } from "@/services/types"
import { HexDisplay } from "./HexDisplay"
import { bytesToHex } from "./verification-utils"

const appRuntime = ManagedRuntime.make(
  FalconService.Default.pipe(Layer.provide(WasmRuntimeLive)),
)

function deriveAddress(packedPk: PackedPublicKey, classHash: string): string {
  const constructorCalldata = [...packedPk.slots]
  return hash.calculateContractAddressFromHash("0x1", classHash, constructorCalldata, 0)
}

function truncateAddress(addr: string): string {
  if (addr.length <= 16) return addr
  return addr.slice(0, 10) + "..." + addr.slice(-6)
}

export function KeyManagementPanel(): React.JSX.Element {
  const keypair = useAtomValue(keypairAtom)
  const packedKey = useAtomValue(packedKeyAtom)
  const step = useAtomValue(verificationStepAtom)
  const setKeypair = useAtomSet(keypairAtom)
  const setPackedKey = useAtomSet(packedKeyAtom)
  const setStep = useAtomSet(verificationStepAtom)
  const setWasmStatus = useAtomSet(wasmStatusAtom)
  const networkId = useAtomValue(networkAtom)
  const networkConfig = NETWORKS[networkId]

  const [showNtt, setShowNtt] = useState(false)
  const [showPacked, setShowPacked] = useState(false)
  const [hasExported, setHasExported] = useState(getExportedFlag)
  const [confirmReplace, setConfirmReplace] = useState<{
    currentAddr: string
    newAddr: string
    proceed: () => void
  } | null>(null)
  const [confirmGenerate, setConfirmGenerate] = useState(false)
  const [exportSuccess, setExportSuccess] = useState(false)

  // Sync exported flag from localStorage when keypair changes
  useEffect(() => {
    setHasExported(getExportedFlag())
  }, [keypair])

  const isBusy = step.step === "generating-keypair"

  // Derive address from current packed key for display
  const currentAddress = Option.match(packedKey, {
    onNone: () => null,
    onSome: (pk) => {
      if (networkConfig.classHash === "0x0") return null
      return deriveAddress(pk, networkConfig.classHash)
    },
  })

  const packPublicKey = useCallback(
    async (pkNtt: Int32Array) => {
      const pkNtt16 = new Uint16Array(pkNtt.length)
      for (let i = 0; i < pkNtt.length; i++) pkNtt16[i] = pkNtt[i]
      const exit = await appRuntime.runPromiseExit(
        FalconService.packPublicKey(pkNtt16),
      )
      if (Exit.isSuccess(exit)) {
        setPackedKey(Option.some(exit.value))
        persistPackedKey(Option.some(exit.value))
      }
    },
    [setPackedKey],
  )

  const doGenerate = useCallback(async () => {
    setConfirmGenerate(false)
    setStep({ step: "generating-keypair" })
    setPackedKey(Option.none())
    persistPackedKey(Option.none())
    const seed = crypto.getRandomValues(new Uint8Array(32))

    const exit = await appRuntime.runPromiseExit(
      FalconService.generateKeypair(seed),
    )

    if (Exit.isSuccess(exit)) {
      const kpOption = Option.some(exit.value)
      setKeypair(kpOption)
      persistKeypair(kpOption)
      setExportedFlag(false)
      setHasExported(false)
      setWasmStatus("ready")
      setStep({ step: "idle" })
      await packPublicKey(exit.value.publicKeyNtt)
    } else {
      const errOpt = Cause.failureOption(exit.cause)
      const msg = Option.match(errOpt, {
        onNone: () => "Keypair generation failed",
        onSome: (e) => e.message,
      })
      setStep({ step: "error", message: msg })
    }
  }, [setKeypair, setPackedKey, setStep, setWasmStatus, packPublicKey])

  const handleGenerate = useCallback(() => {
    // Guard: if keypair already exists, show inline confirmation
    if (Option.isSome(keypair) && Option.isSome(packedKey) && currentAddress) {
      setConfirmGenerate(true)
      return
    }
    doGenerate()
  }, [keypair, packedKey, currentAddress, doGenerate])

  const applyImport = useCallback(
    async (text: string) => {
      const exit = await appRuntime.runPromiseExit(parseKeyFile(text))

      if (Exit.isSuccess(exit)) {
        const kpOption = Option.some(exit.value.keypair)
        const pkOption = Option.some(exit.value.packedPublicKey)
        setKeypair(kpOption)
        setPackedKey(pkOption)
        persistKeypair(kpOption)
        persistPackedKey(pkOption)
        setExportedFlag(true) // imported from file = effectively backed up
        setHasExported(true)
        setWasmStatus("ready")
        setStep({ step: "idle" })
      } else {
        const errOpt = Cause.failureOption(exit.cause)
        const msg = Option.match(errOpt, {
          onNone: () => "Failed to parse key file",
          onSome: (e) => e.message,
        })
        setStep({ step: "error", message: msg })
      }
    },
    [setKeypair, setPackedKey, setWasmStatus, setStep],
  )

  const handleImport = useCallback(() => {
    const input = document.createElement("input")
    input.type = "file"
    input.accept = ".json"
    input.onchange = async () => {
      const file = input.files?.[0]
      if (!file) return
      const text = await file.text()

      // Parse the imported key to check for address mismatch
      const parseExit = await appRuntime.runPromiseExit(parseKeyFile(text))
      if (Exit.isFailure(parseExit)) {
        applyImport(text) // let applyImport show the error
        return
      }

      const importedPk = parseExit.value.packedPublicKey
      const hasExisting = Option.isSome(packedKey)

      if (hasExisting && networkConfig.classHash !== "0x0") {
        const existingPk = Option.getOrThrow(packedKey)
        const existingAddr = deriveAddress(existingPk, networkConfig.classHash)
        const importedAddr = deriveAddress(importedPk, networkConfig.classHash)

        if (existingAddr !== importedAddr) {
          setConfirmReplace({
            currentAddr: existingAddr,
            newAddr: importedAddr,
            proceed: () => {
              setConfirmReplace(null)
              applyImport(text)
            },
          })
          return
        }
      }

      applyImport(text)
    }
    input.click()
  }, [packedKey, networkConfig.classHash, applyImport])

  const handleExport = useCallback(() => {
    const kp = Option.match(keypair, { onNone: () => null, onSome: (k) => k })
    const pk = Option.match(packedKey, { onNone: () => null, onSome: (p) => p })
    if (!kp || !pk) return

    const json = exportKeyFile(kp, pk)
    const blob = new Blob([json], { type: "application/json" })
    const url = URL.createObjectURL(blob)
    const a = document.createElement("a")
    a.href = url
    a.download = "falcon-keypair.json"
    a.click()
    URL.revokeObjectURL(url)
    setExportedFlag(true)
    setHasExported(true)
    setExportSuccess(true)
    setTimeout(() => setExportSuccess(false), 2000)
  }, [keypair, packedKey])

  const hasKeypair = Option.isSome(keypair)
  const hasPacked = Option.isSome(packedKey)

  const keypairHex = Option.match(keypair, {
    onNone: () => null,
    onSome: (kp) => "0x" + bytesToHex(kp.verifyingKey),
  })

  const nttCoeffs = Option.match(keypair, {
    onNone: () => null,
    onSome: (kp) => Array.from(kp.publicKeyNtt),
  })

  const packedSlots = Option.match(packedKey, {
    onNone: () => null,
    onSome: (pk) => pk.slots,
  })

  return (
    <div className="space-y-5">
      <h3 className="text-base font-semibold tracking-tight text-falcon-text/90">Key Management</h3>

      {/* Backup warning */}
      {hasKeypair && !hasExported && (
        <div className="flex items-start gap-3 rounded-xl border border-amber-500/20 bg-amber-500/5 px-4 py-3">
          <span className="mt-0.5 shrink-0 text-amber-400 text-sm">&#9888;</span>
          <div className="flex-1">
            <p className="text-xs font-medium text-amber-300/90">
              Wallet not backed up
            </p>
            <p className="mt-0.5 text-xs text-amber-300/50">
              Export your key file now to avoid losing access to your funds.
            </p>
          </div>
          <button
            onClick={handleExport}
            className="shrink-0 rounded-lg bg-amber-500/15 px-3 py-1.5 text-xs font-medium text-amber-300/90 transition-colors hover:bg-amber-500/25"
          >
            Export Now
          </button>
        </div>
      )}

      {/* Generate replacement confirmation */}
      {confirmGenerate && currentAddress && (
        <div className="rounded-xl border border-amber-500/20 bg-amber-500/5 p-4 space-y-3 animate-fade-in">
          <p className="text-xs font-medium text-amber-300/90">
            Replace existing wallet?
          </p>
          <p className="text-xs text-amber-300/60">
            You already have a wallet at <span className="font-mono text-amber-300/80">{truncateAddress(currentAddress)}</span>.
            Generating a new key will replace it. Make sure you&apos;ve exported your current key first.
          </p>
          <div className="flex gap-2">
            <button
              onClick={doGenerate}
              className="rounded-lg bg-amber-500/15 px-4 py-1.5 text-xs font-medium text-amber-300/90 transition-colors hover:bg-amber-500/25"
            >
              Replace Wallet
            </button>
            <button
              onClick={() => setConfirmGenerate(false)}
              className="glass-btn rounded-lg px-4 py-1.5 text-xs font-medium text-falcon-text/40 transition-colors hover:text-falcon-text/70"
            >
              Cancel
            </button>
          </div>
        </div>
      )}

      {/* Import mismatch confirmation dialog */}
      {confirmReplace && (
        <div className="rounded-xl border border-red-500/20 bg-red-500/5 p-4 space-y-3">
          <p className="text-xs font-medium text-red-300/90">
            Address mismatch detected
          </p>
          <p className="text-xs text-red-300/60">
            Your current wallet is at <span className="font-mono text-red-300/80">{truncateAddress(confirmReplace.currentAddr)}</span>.
            The imported key maps to a different address: <span className="font-mono text-red-300/80">{truncateAddress(confirmReplace.newAddr)}</span>.
          </p>
          <p className="text-xs text-red-300/60">
            Importing will replace your current wallet. Any funds at the old address will only be accessible if you have a backup.
          </p>
          <div className="flex gap-2">
            <button
              onClick={confirmReplace.proceed}
              className="rounded-lg bg-red-500/15 px-4 py-1.5 text-xs font-medium text-red-300/90 transition-colors hover:bg-red-500/25"
            >
              Replace Wallet
            </button>
            <button
              onClick={() => setConfirmReplace(null)}
              className="glass-btn rounded-lg px-4 py-1.5 text-xs font-medium text-falcon-text/40 transition-colors hover:text-falcon-text/70"
            >
              Cancel
            </button>
          </div>
        </div>
      )}

      <div className="flex flex-wrap gap-2">
        <button
          onClick={handleGenerate}
          disabled={isBusy}
          className="rounded-xl bg-gradient-to-b from-falcon-primary to-falcon-primary/80 px-5 py-2.5 text-sm font-semibold text-white shadow-md shadow-falcon-primary/15 transition-all duration-200 hover:scale-[1.02] hover:shadow-lg hover:shadow-falcon-primary/20 disabled:cursor-not-allowed disabled:opacity-40 disabled:hover:scale-100"
        >
          {isBusy ? "Generating..." : "Generate"}
        </button>
        <button
          onClick={handleImport}
          disabled={isBusy}
          className="glass-btn rounded-xl px-5 py-2.5 text-sm font-medium text-falcon-text/60 transition-all duration-200 hover:scale-[1.02] hover:text-falcon-text/80 disabled:cursor-not-allowed disabled:opacity-40"
        >
          Import
        </button>
        <button
          onClick={handleExport}
          disabled={!hasKeypair || !hasPacked}
          className={`glass-btn rounded-xl px-5 py-2.5 text-sm font-medium transition-all duration-200 hover:scale-[1.02] disabled:cursor-not-allowed disabled:opacity-40 ${
            exportSuccess
              ? "text-falcon-success/80"
              : "text-falcon-text/60 hover:text-falcon-text/80"
          }`}
        >
          {exportSuccess ? "\u2713 Exported" : "Export"}
        </button>
      </div>

      {keypairHex !== null && (
        <div className="space-y-4">
          <HexDisplay
            label="Verifying Key (896-byte h polynomial)"
            value={keypairHex}
            truncate={{ head: 18, tail: 8 }}
          />

          {/* Address display — always show when key exists */}
          {currentAddress && (
            <div className="glass-card-static rounded-xl p-3">
              <p className="text-[10px] font-medium tracking-widest text-falcon-text/20 uppercase">
                Your Starknet Address
              </p>
              <p className="mt-1 break-all font-mono text-xs text-falcon-accent/70">
                {currentAddress}
              </p>
            </div>
          )}

          {nttCoeffs !== null && (
            <div>
              <button
                onClick={() => setShowNtt(!showNtt)}
                className="flex items-center gap-1.5 text-xs font-medium text-falcon-text/30 transition-colors duration-200 hover:text-falcon-text/60"
              >
                <span className="text-[10px]">{showNtt ? "\u25BC" : "\u25B6"}</span>
                NTT Coefficients ({nttCoeffs.length})
              </button>
              {showNtt && (
                <div className="glass-display mt-2 max-h-32 overflow-y-auto rounded-lg px-3 py-2 font-mono text-xs text-falcon-accent/50">
                  [{nttCoeffs.slice(0, 20).join(", ")}
                  {nttCoeffs.length > 20 && `, ... ${nttCoeffs.length - 20} more`}]
                </div>
              )}
            </div>
          )}

          {packedSlots !== null && (
            <div>
              <button
                onClick={() => setShowPacked(!showPacked)}
                className="flex items-center gap-1.5 text-xs font-medium text-falcon-text/30 transition-colors duration-200 hover:text-falcon-text/60"
              >
                <span className="text-[10px]">{showPacked ? "\u25BC" : "\u25B6"}</span>
                Packed Public Key ({packedSlots.length} felt252 slots)
              </button>
              {showPacked && (
                <HexDisplay
                  label=""
                  value={packedSlots}
                  maxRows={29}
                  truncate={{ head: 18, tail: 8 }}
                />
              )}
            </div>
          )}
        </div>
      )}
    </div>
  )
}

"use client"

import React, { useCallback } from "react"
import { Cause, Exit, Layer, ManagedRuntime, Option } from "effect"
import { useAtomValue, useAtomSet } from "@effect-atom/atom-react"
import { FalconService } from "@/services/FalconService"
import { WasmRuntimeLive } from "@/services/WasmRuntime"
import {
  keypairAtom,
  messageAtom,
  packedKeyAtom,
  signatureAtom,
  verificationStepAtom,
} from "@/atoms/falcon"
import { HexDisplay } from "./HexDisplay"
import { bytesToHex, getVerificationDisabledState } from "./verification-utils"

const appRuntime = ManagedRuntime.make(
  FalconService.Default.pipe(Layer.provide(WasmRuntimeLive)),
)

export function SignVerifyPanel(): React.JSX.Element {
  const message = useAtomValue(messageAtom)
  const keypair = useAtomValue(keypairAtom)
  const step = useAtomValue(verificationStepAtom)
  const signature = useAtomValue(signatureAtom)

  const setMessage = useAtomSet(messageAtom)
  const setStep = useAtomSet(verificationStepAtom)
  const setSignature = useAtomSet(signatureAtom)
  const setPackedKey = useAtomSet(packedKeyAtom)

  const { isBusy, canSign } = getVerificationDisabledState({
    keypair,
    message,
    step,
  })

  const handleSignAndVerify = useCallback(async () => {
    const kp = Option.match(keypair, {
      onNone: () => null,
      onSome: (k) => k,
    })
    if (!kp) return

    const startTime = Date.now()
    const messageBytes = new TextEncoder().encode(message)

    setStep({ step: "signing" })
    const signExit = await appRuntime.runPromiseExit(
      FalconService.sign(kp.secretKey, messageBytes),
    )

    if (Exit.isFailure(signExit)) {
      const errOpt = Cause.failureOption(signExit.cause)
      const msg = Option.match(errOpt, {
        onNone: () => "Signing failed",
        onSome: (e) => e.message,
      })
      setStep({ step: "error", message: msg })
      return
    }

    const sigResult = signExit.value
    setSignature(Option.some(sigResult))

    setStep({ step: "packing" })
    const pkNtt16 = new Uint16Array(kp.publicKeyNtt.length)
    for (let i = 0; i < kp.publicKeyNtt.length; i++) {
      pkNtt16[i] = kp.publicKeyNtt[i]
    }
    const packExit = await appRuntime.runPromiseExit(
      FalconService.packPublicKey(pkNtt16),
    )

    if (Exit.isFailure(packExit)) {
      const errOpt = Cause.failureOption(packExit.cause)
      const msg = Option.match(errOpt, {
        onNone: () => "Packing failed",
        onSome: (e) => e.message,
      })
      setStep({ step: "error", message: msg })
      return
    }

    setPackedKey(Option.some(packExit.value))

    setStep({ step: "verifying", substep: "verify" })
    const verifyExit = await appRuntime.runPromiseExit(
      FalconService.verify(kp.verifyingKey, messageBytes, sigResult.signature),
    )

    if (Exit.isFailure(verifyExit)) {
      const errOpt = Cause.failureOption(verifyExit.cause)
      const msg = Option.match(errOpt, {
        onNone: () => "Verification failed",
        onSome: (e) => e.message,
      })
      setStep({ step: "error", message: msg })
      return
    }

    const durationMs = Date.now() - startTime
    setStep({ step: "complete", valid: verifyExit.value, durationMs })
  }, [keypair, message, setPackedKey, setSignature, setStep])

  const signatureHex = Option.match(signature, {
    onNone: () => null,
    onSome: (s) => "0x" + bytesToHex(s.signature),
  })

  const saltHex = Option.match(signature, {
    onNone: () => null,
    onSome: (s) => "0x" + bytesToHex(s.salt),
  })

  return (
    <div className="space-y-5">
      <h3 className="text-base font-semibold tracking-tight text-falcon-text/90">Sign & Verify</h3>

      <div>
        <label
          htmlFor="message-input"
          className="block text-xs font-medium text-falcon-text/30"
        >
          Message
        </label>
        <input
          id="message-input"
          type="text"
          value={message}
          onChange={(e) => setMessage(e.target.value)}
          disabled={isBusy}
          placeholder="Enter a message to sign..."
          className="glass-input mt-2 w-full px-4 py-3 font-mono text-sm text-falcon-text/80 placeholder-falcon-text/20"
        />
      </div>

      <button
        onClick={handleSignAndVerify}
        aria-label="Sign and verify message"
        disabled={!canSign}
        className="inline-flex items-center gap-2 rounded-xl bg-gradient-to-b from-falcon-accent to-falcon-accent/80 px-7 py-3 text-sm font-semibold text-white shadow-md shadow-falcon-accent/15 transition-all duration-200 hover:scale-[1.02] hover:shadow-lg hover:shadow-falcon-accent/20 active:scale-[0.98] focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-falcon-accent/40 disabled:cursor-not-allowed disabled:opacity-40 disabled:hover:scale-100"
      >
        {(step.step === "signing" || step.step === "packing" || step.step === "verifying") ? (
          <>
            <svg className="animate-spin-ring" width="20" height="20" viewBox="0 0 20 20" fill="none">
              <circle cx="10" cy="10" r="7" stroke="currentColor" strokeWidth="2" strokeLinecap="round" className="opacity-20" />
              <circle cx="10" cy="10" r="7" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeDasharray="33" strokeDashoffset="23" />
            </svg>
            {step.step === "signing" ? "Signing..." : step.step === "packing" ? "Packing..." : "Verifying..."}
          </>
        ) : (
          "Sign & Verify"
        )}
      </button>

      {signatureHex !== null && step.step === "complete" && (
        <div className="space-y-3">
          <HexDisplay
            label={`Signature (${Option.match(signature, { onNone: () => 0, onSome: (s) => s.signature.length })} bytes)`}
            value={signatureHex}
            truncate={{ head: 18, tail: 8 }}
          />
          {saltHex !== null && (
            <HexDisplay
              label={`Salt (${Option.match(signature, { onNone: () => 0, onSome: (s) => s.salt.length })} bytes)`}
              value={saltHex}
              truncate={{ head: 18, tail: 8 }}
            />
          )}
        </div>
      )}

      {step.step === "complete" && (
        <div
          role="status"
          aria-live="polite"
          className={`glass-card-static rounded-2xl p-5 animate-fade-in ${step.valid ? "glass-card-success" : "glass-card-error"}`}
        >
          <div className="flex items-center gap-3">
            <span className={`text-lg font-semibold ${step.valid ? "text-falcon-success" : "text-falcon-error"}`}>
              {step.valid ? "\u2713" : "\u2717"}
            </span>
            <span className="text-sm font-medium text-falcon-text/80">
              {step.valid ? "Signature valid" : "Signature invalid"}
            </span>
            <span className="ml-auto font-mono tabular-nums text-xs text-falcon-text/30">{step.durationMs}ms</span>
          </div>
        </div>
      )}

      {step.step === "error" && (
        <div
          role="alert"
          aria-live="polite"
          className="glass-card-static glass-card-error rounded-2xl p-5 animate-fade-in"
        >
          <div className="flex items-start gap-3">
            <span className="text-lg font-semibold text-falcon-error">{"\u2717"}</span>
            <div className="flex-1">
              <p className="text-sm font-medium text-falcon-error/80">Error</p>
              <p className="mt-1 break-all text-xs text-falcon-text/30">{step.message}</p>
            </div>
            <button
              onClick={() => setStep({ step: "idle" })}
              className="glass-btn ml-auto rounded-lg px-3 py-1 text-xs text-falcon-text/40 hover:text-falcon-text/70"
            >
              Try Again
            </button>
          </div>
        </div>
      )}
    </div>
  )
}

"use client"

import React, { useCallback, useEffect, useRef, useState } from "react"
import { Exit, Option } from "effect"
import { useAtomValue } from "@effect-atom/atom-react"
import { transaction } from "starknet"
import type { InvocationsSignerDetails, constants } from "starknet"
import { keypairAtom } from "@/atoms/falcon"
import { networkAtom } from "@/atoms/starknet"
import { NETWORKS } from "@/config/networks"
import { StarknetService, STRK_TOKEN_ADDRESS } from "@/services/StarknetService"
import type { FalconResourceBounds } from "@/services/StarknetService"
import { FalconSigner } from "@/services/FalconSigner"
import { extractUserMessage } from "@/services/error-messages"
import { ExplorerLink } from "@/components/ui/ExplorerLink"
import { TransactionPhases } from "@/components/ui/TransactionPhases"
import type { ContractAddress } from "@/services/types"
import type { ManagedRuntime } from "effect"
import type { FalconService } from "@/services/FalconService"

type TxPhase =
  | { phase: "idle" }
  | { phase: "prefetching" }
  | { phase: "signing" }
  | { phase: "submitting"; signMs: number }
  | { phase: "confirming"; signMs: number; txHash: string }
  | { phase: "done"; signMs: number; networkMs: number; txHash: string }
  | { phase: "error"; message: string }

interface Prefetched {
  nonce: string
  chainId: string
  resourceBounds: FalconResourceBounds
}

interface SendTransactionProps {
  readonly deployedAddress: ContractAddress
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  readonly deployRuntime: ManagedRuntime.ManagedRuntime<FalconService | StarknetService, any>
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  readonly falconRuntime: ManagedRuntime.ManagedRuntime<FalconService, any>
}

/** Yield to the browser so it can paint before we continue. */
const yieldToBrowser = () => new Promise<void>((r) => setTimeout(r, 0))

export function SendTransaction({
  deployedAddress,
  deployRuntime,
  falconRuntime,
}: SendTransactionProps): React.JSX.Element {
  const keypair = useAtomValue(keypairAtom)
  const networkId = useAtomValue(networkAtom)
  const networkConfig = NETWORKS[networkId]

  const [recipient, setRecipient] = useState(deployedAddress as string)
  const [amount, setAmount] = useState("0.001")
  const [txPhase, setTxPhase] = useState<TxPhase>({ phase: "prefetching" })
  const [recipientTouched, setRecipientTouched] = useState(false)
  const [accountBalance, setAccountBalance] = useState<bigint | null>(null)

  const timingRef = useRef({ signMs: 0, networkStartedAt: 0 })

  // Fetch balance on mount
  useEffect(() => {
    let cancelled = false
    const fetchBal = async () => {
      const exit = await deployRuntime.runPromiseExit(
        StarknetService.getBalance(deployedAddress as string),
      )
      if (!cancelled && Exit.isSuccess(exit)) {
        setAccountBalance(exit.value)
      }
    }
    fetchBal()
    return () => { cancelled = true }
  }, [deployRuntime, deployedAddress])

  // Address validation
  const recipientValid = /^0x[0-9a-fA-F]{1,64}$/.test(recipient)
  const isSelf = (deployedAddress as string) === recipient

  // Amount validation
  const parsedAmount = parseFloat(amount)
  const amountWei = isNaN(parsedAmount) ? 0n : BigInt(Math.floor(parsedAmount * 1e18))
  const exceedsBalance = accountBalance != null && amountWei > accountBalance
  const overHalf = accountBalance != null && accountBalance > 0n && amountWei > accountBalance / 2n && !exceedsBalance

  // Prefetch nonce + chainId + resource bounds so send goes straight to signing
  const prefetchRef = useRef<Prefetched | null>(null)

  const doPrefetch = useCallback(async () => {
    prefetchRef.current = null
    const [nonceExit, chainExit, rbExit] = await Promise.all([
      deployRuntime.runPromiseExit(StarknetService.getNonce(deployedAddress as string)),
      deployRuntime.runPromiseExit(StarknetService.getChainId()),
      deployRuntime.runPromiseExit(StarknetService.getResourceBounds()),
    ])
    if (Exit.isSuccess(nonceExit) && Exit.isSuccess(chainExit) && Exit.isSuccess(rbExit)) {
      prefetchRef.current = {
        nonce: nonceExit.value,
        chainId: chainExit.value,
        resourceBounds: rbExit.value,
      }
      return true
    }
    return false
  }, [deployRuntime, deployedAddress])

  useEffect(() => {
    let cancelled = false
    const init = async () => {
      // Retry prefetch up to 3 times with delay for post-deploy nonce propagation
      for (let attempt = 0; attempt < 3; attempt++) {
        if (cancelled) return
        const ok = await doPrefetch()
        if (ok) {
          if (!cancelled) setTxPhase({ phase: "idle" })
          return
        }
        // Wait a bit for the node to update nonce after deploy
        await new Promise((r) => setTimeout(r, 1500))
      }
      if (!cancelled) {
        setTxPhase({ phase: "idle" }) // show UI even if prefetch partially failed
      }
    }
    init()
    return () => { cancelled = true }
  }, [doPrefetch])

  const handleSend = useCallback(async () => {
    const kp = Option.match(keypair, { onNone: () => null, onSome: (k) => k })
    if (!kp) return

    let prefetched = prefetchRef.current
    if (!prefetched) {
      setTxPhase({ phase: "prefetching" })
      const ok = await doPrefetch()
      prefetched = prefetchRef.current
      if (!ok || !prefetched) {
        setTxPhase({ phase: "error", message: "Network data not ready. Please try again." })
        return
      }
    }

    // ── Phase 1: Sign ───────────────────────────────────────────────
    setTxPhase({ phase: "signing" })

    const signer = new FalconSigner(kp.secretKey, kp.publicKeyNtt, falconRuntime)

    const calls = [{
      contractAddress: STRK_TOKEN_ADDRESS,
      entrypoint: "transfer",
      calldata: [recipient, BigInt(Math.floor(parseFloat(amount) * 1e18)).toString(), "0"],
    }]

    const signerDetails: InvocationsSignerDetails = {
      walletAddress: deployedAddress as string,
      chainId: prefetched.chainId as constants.StarknetChainId,
      cairoVersion: "1",
      version: "0x3",
      nonce: prefetched.nonce,
      resourceBounds: prefetched.resourceBounds,
      tip: "0x0",
      paymasterData: [],
      accountDeploymentData: [],
      nonceDataAvailabilityMode: "L1",
      feeDataAvailabilityMode: "L1",
    }

    const signStart = performance.now()
    let signature: string[]
    try {
      signature = await signer.signTransaction(calls, signerDetails) as string[]
    } catch (err) {
      setTxPhase({ phase: "error", message: String(err) })
      return
    }
    const signMs = performance.now() - signStart

    // Update UI and yield so the browser paints the signing badge
    timingRef.current = { signMs, networkStartedAt: performance.now() }
    setTxPhase({ phase: "submitting", signMs })
    await yieldToBrowser()

    // ── Phase 2: Submit ─────────────────────────────────────────────
    const compiledCalldata = transaction.getExecuteCalldata(calls, signerDetails.cairoVersion)

    const submitExit = await deployRuntime.runPromiseExit(
      StarknetService.submitSignedInvoke(
        deployedAddress as string,
        compiledCalldata as string[],
        signature,
        prefetched.nonce,
        prefetched.resourceBounds,
      ),
    )

    if (Exit.isFailure(submitExit)) {
      const msg = extractUserMessage(submitExit, "Transaction failed")
      // If nonce conflict, refetch and let user retry
      if (msg.toLowerCase().includes("nonce")) {
        await doPrefetch()
        setTxPhase({ phase: "error", message: "Transaction nonce conflict. Wait for your previous transaction to confirm, then try again." })
      } else {
        setTxPhase({ phase: "error", message: msg })
        doPrefetch()
      }
      return
    }

    const { txHash } = submitExit.value
    setTxPhase({ phase: "confirming", signMs, txHash })

    // ── Phase 3: Confirm ────────────────────────────────────────────
    const waitExit = await deployRuntime.runPromiseExit(
      StarknetService.waitForTx(txHash),
    )

    // Refetch nonce for next transaction
    doPrefetch()

    if (Exit.isFailure(waitExit)) {
      setTxPhase({ phase: "error", message: extractUserMessage(waitExit, "Transaction confirmation failed") })
      return
    }

    const networkMs = performance.now() - timingRef.current.networkStartedAt
    setTxPhase({ phase: "done", signMs, networkMs, txHash })
  }, [keypair, deployedAddress, recipient, amount, deployRuntime, falconRuntime, doPrefetch])

  const isBusy =
    txPhase.phase === "signing" ||
    txPhase.phase === "submitting" ||
    txPhase.phase === "confirming" ||
    txPhase.phase === "prefetching"

  return (
    <div className="glass-card-static mt-8 rounded-2xl p-6">
      <h3 className="text-base font-semibold tracking-tight text-falcon-text/90">Test Your Falcon Account</h3>
      <p className="mt-1.5 text-xs text-falcon-text/30">
        Send a small amount of STRK to yourself to verify your post-quantum account works correctly.
      </p>

      <div className="mt-5 space-y-4">
        <div>
          <label htmlFor="tx-recipient" className="block text-xs font-medium text-falcon-text/30">
            Recipient
            {isSelf && (
              <span className="ml-2 inline-flex items-center rounded-md bg-falcon-primary/10 px-1.5 py-0.5 text-[10px] font-medium text-falcon-primary/70">
                You
              </span>
            )}
          </label>
          <div className="relative mt-2">
            <input
              id="tx-recipient"
              type="text"
              value={recipient}
              onChange={(e) => setRecipient(e.target.value)}
              onBlur={() => setRecipientTouched(true)}
              className={`glass-input w-full px-4 py-3 pr-10 font-mono text-sm text-falcon-text/80 ${
                recipientTouched && !recipientValid ? "!border-falcon-error/30" : ""
              }`}
            />
            {recipientTouched && recipient.length > 0 && (
              <span className={`absolute right-3 top-1/2 -translate-y-1/2 text-sm font-semibold ${
                recipientValid ? "text-falcon-success/70" : "text-falcon-error/70"
              }`}>
                {recipientValid ? "\u2713" : "\u2717"}
              </span>
            )}
          </div>
          {recipientTouched && !recipientValid && recipient.length > 0 && (
            <p className="mt-1 text-[11px] text-falcon-error/60">
              Must be a hex address starting with 0x (up to 66 characters)
            </p>
          )}
        </div>

        <div>
          <label htmlFor="tx-amount" className="flex items-baseline gap-2 text-xs font-medium text-falcon-text/30">
            <span>Amount (STRK)</span>
            {accountBalance != null && (
              <span className="ml-auto text-[10px] text-falcon-text/20 tabular-nums">
                Available: {formatStrk(accountBalance)}
              </span>
            )}
          </label>
          <input
            id="tx-amount"
            type="text"
            value={amount}
            onChange={(e) => setAmount(e.target.value)}
            className={`glass-input mt-2 w-full px-4 py-3 font-mono text-sm text-falcon-text/80 ${
              exceedsBalance ? "!border-falcon-error/30" : ""
            }`}
          />
          {exceedsBalance && (
            <p className="mt-1 text-[11px] text-falcon-error/60">Insufficient balance</p>
          )}
          {overHalf && (
            <p className="mt-1 text-[11px] text-amber-400/60">This is more than half your balance</p>
          )}
        </div>

        <button
          onClick={handleSend}
          disabled={isBusy || !Option.isSome(keypair) || !recipientValid || exceedsBalance}
          className="rounded-xl bg-gradient-to-b from-falcon-accent to-falcon-accent/80 px-7 py-3 text-sm font-semibold text-white shadow-md shadow-falcon-accent/15 transition-all duration-200 hover:scale-[1.02] hover:shadow-lg hover:shadow-falcon-accent/20 active:scale-[0.98] focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-falcon-accent/40 disabled:cursor-not-allowed disabled:opacity-40 disabled:hover:scale-100"
        >
          {txPhase.phase === "prefetching" ? "Preparing..." : isBusy ? "Sending..." : "Send STRK"}
        </button>
      </div>

      {(txPhase.phase === "signing" || txPhase.phase === "submitting" || txPhase.phase === "confirming") && (
        <TransactionPhases
          phase={txPhase.phase}
          signMs={"signMs" in txPhase ? txPhase.signMs : undefined}
        />
      )}

      {txPhase.phase === "done" && (
        <div className="glass-card-static glass-card-success mt-5 rounded-2xl p-5 animate-fade-in animate-success-shimmer">
          <p className="text-sm font-medium text-falcon-success/80">Transaction Confirmed</p>
          <div className="mt-3 flex flex-wrap gap-3">
            <span className="inline-flex items-center gap-1.5 rounded-lg bg-falcon-success/10 px-2.5 py-1 text-xs font-medium tabular-nums text-falcon-success/80">
              Signed in {formatMs(txPhase.signMs)}
            </span>
            <span className="inline-flex items-center gap-1.5 rounded-lg bg-falcon-accent/10 px-2.5 py-1 text-xs font-medium tabular-nums text-falcon-accent/80">
              Network in {formatMs(txPhase.networkMs)}
            </span>
          </div>
          <p className="mt-3 break-all font-mono tabular-nums text-xs text-falcon-text/50">
            Tx: {txPhase.txHash}
          </p>
          <ExplorerLink baseUrl={networkConfig.explorerBaseUrl} txHash={txPhase.txHash} className="mt-3" />
        </div>
      )}

      {txPhase.phase === "error" && (
        <div className="glass-card-static glass-card-error mt-5 rounded-2xl p-5 animate-fade-in">
          <p className="text-sm text-falcon-error/80">{txPhase.message}</p>
        </div>
      )}
    </div>
  )
}

function formatMs(ms: number): string {
  if (ms < 1000) return `${Math.round(ms)}ms`
  return `${(ms / 1000).toFixed(1)}s`
}

function formatStrk(wei: bigint): string {
  const whole = wei / 10n ** 18n
  const frac = wei % 10n ** 18n
  const fracStr = frac.toString().padStart(18, "0").slice(0, 4)
  return `${whole}.${fracStr} STRK`
}

import React from "react"

interface TransactionPhasesProps {
  /** Current active phase */
  readonly phase: "signing" | "submitting" | "confirming"
  /** Duration of signing phase in ms (set when signing completes) */
  readonly signMs?: number
}

const PHASES = [
  { key: "signing", label: "Falcon-512 Signing", activeLabel: "signing..." },
  { key: "submitting", label: "Submitting to Network", activeLabel: "broadcasting..." },
  { key: "confirming", label: "Awaiting Confirmation", activeLabel: "waiting..." },
] as const

const PHASE_ORDER: Record<string, number> = {
  signing: 0, submitting: 1, confirming: 2,
}

export function TransactionPhases({ phase, signMs }: TransactionPhasesProps) {
  const activeIdx = PHASE_ORDER[phase]

  return (
    <div
      role="status"
      aria-live="polite"
      className="glass-card-static glass-card-active mt-5 overflow-hidden rounded-2xl animate-fade-in"
    >
      {/* Indeterminate progress bar */}
      <div className="relative h-[2px] w-full overflow-hidden bg-falcon-accent/10">
        <div className="absolute inset-y-0 w-1/3 rounded-full bg-gradient-to-r from-transparent via-falcon-accent/60 to-transparent animate-progress-indeterminate" />
      </div>

      <div className="px-5 py-4 space-y-0">
        {PHASES.map((p, i) => {
          const isDone = i < activeIdx
          const isActive = i === activeIdx
          const isPending = i > activeIdx

          // Show duration badge for signing phase only
          const durationLabel = isDone && p.key === "signing" && signMs != null ? formatMs(signMs) : null

          return (
            <div
              key={p.key}
              className={`flex items-center gap-3 py-2 transition-opacity duration-300 ${
                isPending ? "opacity-25" : "opacity-100"
              }`}
            >
              {/* Phase indicator */}
              <div className="flex h-7 w-7 shrink-0 items-center justify-center">
                {isDone ? (
                  <div className="flex h-5 w-5 items-center justify-center rounded-full bg-falcon-success/15 text-falcon-success animate-scale-in">
                    <CheckIcon />
                  </div>
                ) : isActive ? (
                  <svg
                    className="animate-spin-ring"
                    width="20"
                    height="20"
                    viewBox="0 0 20 20"
                    fill="none"
                  >
                    <circle
                      cx="10" cy="10" r="7"
                      stroke="currentColor"
                      strokeWidth="2"
                      strokeLinecap="round"
                      className="text-falcon-accent/10"
                    />
                    <circle
                      cx="10" cy="10" r="7"
                      stroke="currentColor"
                      strokeWidth="2"
                      strokeLinecap="round"
                      strokeDasharray="33"
                      strokeDashoffset="23"
                      className="text-falcon-accent"
                    />
                  </svg>
                ) : (
                  <div className="h-1.5 w-1.5 rounded-full bg-falcon-text/15" />
                )}
              </div>

              {/* Label */}
              <span className={`text-sm transition-colors duration-200 ${
                isActive
                  ? "font-medium text-falcon-text/80"
                  : isDone
                    ? "text-falcon-text/50"
                    : "text-falcon-text/25"
              }`}>
                {p.label}
              </span>

              {/* Duration badge (signing only) */}
              {isDone && durationLabel != null && (
                <span className="ml-auto rounded-md bg-falcon-success/10 px-2 py-0.5 text-[11px] font-medium tabular-nums text-falcon-success/80 animate-fade-in">
                  {durationLabel}
                </span>
              )}

              {/* Active breathing indicator */}
              {isActive && (
                <span className="ml-auto text-[11px] tabular-nums text-falcon-text/25 animate-text-breathe">
                  {p.activeLabel}
                </span>
              )}
            </div>
          )
        })}
      </div>
    </div>
  )
}

function CheckIcon() {
  return (
    <svg width="10" height="10" viewBox="0 0 10 10" fill="none">
      <path
        d="M2 5.5L4 7.5L8 3"
        stroke="currentColor"
        strokeWidth="1.5"
        strokeLinecap="round"
        strokeLinejoin="round"
      />
    </svg>
  )
}

function formatMs(ms: number): string {
  if (ms < 1000) return `${Math.round(ms)}ms`
  return `${(ms / 1000).toFixed(1)}s`
}

import React from "react"
import { CopyButton } from "./CopyButton"

interface AddressDisplayProps {
  readonly address: string
  readonly label?: string
  readonly explorerBaseUrl?: string
  readonly full?: boolean
  readonly className?: string
}

function truncateAddress(addr: string): string {
  if (addr.length <= 16) return addr
  return `${addr.slice(0, 10)}\u2026${addr.slice(-4)}`
}

export function AddressDisplay({ address, label, explorerBaseUrl, full = false, className = "" }: AddressDisplayProps) {
  return (
    <div className={`glass-display rounded-xl p-4 ${className}`}>
      {label && (
        <p className="text-[10px] font-medium uppercase tracking-widest text-falcon-text/20">
          {label}
        </p>
      )}
      <div className={`flex items-center gap-2 ${label ? "mt-2" : ""}`}>
        <code className="flex-1 break-all font-mono text-xs tabular-nums text-falcon-accent/60">
          {full ? address : truncateAddress(address)}
        </code>
        <CopyButton value={address} />
      </div>
      {explorerBaseUrl && (
        <a
          href={`${explorerBaseUrl}/contract/${address}`}
          target="_blank"
          rel="noreferrer noopener"
          className="mt-2 inline-block text-xs text-falcon-text/25 transition-colors duration-200 hover:text-falcon-accent/60"
        >
          View on explorer &rarr;
        </a>
      )}
    </div>
  )
}

